import HealthKit

let healthStore = HKHealthStore()

if HKHealthStore.isHealthDataAvailable() {
    let stepType = HKQuantityType.quantityType(forIdentifier: .stepCount)!
    healthStore.requestAuthorization(toShare: [], read: [stepType]) { success, error in
        if success {
            let predicate = HKQuery.predicateForSamples(withStart: .now.addingTimeInterval(-86400), end: .now)
            let query = HKStatisticsQuery(quantityType: stepType, quantitySamplePredicate: predicate, options: .cumulativeSum) { _, result, _ in
                if let sum = result?.sumQuantity() {
                    print("🚶 Schritte: \(sum.doubleValue(for: .count()))")
                }
            }
            healthStore.execute(query)
        }
    }
}

import HealthKit

let store = HKHealthStore()
let type = HKQuantityType.quantityType(forIdentifier: .heartRate)!

let query = HKSampleQuery(sampleType: type, predicate: nil, limit: 10, sortDescriptors: nil) { _, samples, _ in
    samples?.forEach { sample in
        if let quantitySample = sample as? HKQuantitySample {
            let bpm = quantitySample.quantity.doubleValue(for: HKUnit(from: "count/min"))
            print("❤️ BPM: \(bpm)")
        }
    }
}
store.execute(query)

